The expected approach is to use Prefix Sum Technique along with Hashing. We can iterate over `arr[]` while maintaining a hash map or dictionary to keep track of the first occurrence of `(prefix sum % k)` at each index. For each index `i`, the longest subarray ending at `i` and having sum divisible by `k` will be equal to `i - first occurrence of (prefix sum[i] % k)`.

Here is a C++ code that implements this approach:

```cpp
#include <iostream>
#include <unordered_map>
#include <vector>

using namespace std;

int longestSubarrayDivK(vector<int>& arr, int k) {
    int n = arr.size(), res = 0;
    unordered_map<int, int> prefIdx;
    int sum = 0;

    // Iterate over all ending points
    for (int i = 0; i < n; i++) {
        // prefix sum mod k (handling negative prefix sum)
        sum = ((sum + arr[i]) % k + k) % k;

        // If sum == 0, then update result with the length of subarray arr[0...i]
        if (sum == 0)
            res = i + 1;

        // Update max length for repeating sum
        else if (prefIdx.find(sum) != prefIdx.end()) {
            res = max(res, i - prefIdx[sum]);
        }

        // Store the first occurrence of sum
        else {
            prefIdx[sum] = i;
        }
    }
    return res;
}

int main() {
    vector<int> arr = {2, 7, 6, 1, 4, 5};
    int k = 3;
    cout << longestSubarrayDivK(arr, k);
    return 0;
}
```

This code works by maintaining a prefix sum for each subarray and checking if the prefix sum modulo `k` is equal to zero. If it is, we update our maximum length of subarray ending at index `i`. We also keep track of the first occurrence of `(prefix sum % k)` using a hash map or dictionary.

class Solution:
    def solve(self, arr, k):
        n = len(arr)
        if n == 0:
            return 0

        # Hash map to store the first index of each remainder
        rem_index = {}
        rem_index[0] = -1  # Initialize with a remainder of 0 at index -1 (no elements considered yet)

        cumulative_sum = 0
        max_length = 0

        for i in range(n):
            cumulative_sum += arr[i]
            current_remainder = cumulative_sum % k

            # If the remainder is negative, we need to adjust it by adding k
            if current_remainder < 0:
                current_remainder += k

            # Check if this remainder has been seen before
            if current_remainder in rem_index:
                # Calculate the length of the subarray ending at index i
                length = i - rem_index[current_remainder]
                max_length = max(max_length, length)
            else:
                # Store the first occurrence of this remainder
                rem_index[current_remainder] = i

        return max_length
